payload.raw:
{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第1–2月",
      "title": "材料与硬件攻坚",
      "description": "完成仿水膜-鱼网结构液态金属基导电薄膜与低迟滞聚氨酯介质复合材料体系开发，构建融合光纤传感与IMU的混合传感架构，实现0.1mm级空间分辨率，并完成柔性传感器阵列微结构设计、材料工艺优化及信号标定。"
    },
    {
      "date": "第3月",
      "title": "算法模型开发",
      "description": "开发轻量化分层CNN-LSTM手势识别模型，结合时序滑动窗口分割与噪声抑制模块，实现实测准确率>98.2%的毫秒级实时推理；同步构建视觉-触觉-听觉统一时空对齐协议，提升多模态融合效率60%。"
    },
    {
      "date": "第4月",
      "title": "系统集成联调",
      "description": "集成多模态交互协议栈，嵌入微型电磁致动器阵列与半导体温控模块组成的压力/温度动态反馈执行单元，构建感知-意图-反馈闭环，并完成软硬件联调及H-Box全息舱、李未可眼镜等合作设备接口对接。"
    },
    {
      "date": "第5–6月",
      "title": "场景验证优化",
      "description": "依托工业远程操控与虚拟实训等真实场景开展压力测试，通过用户反馈采集系统进行多轮体验迭代，验证高保真触觉反馈（微秒级调控）与复杂工况鲁棒性，形成可复用的元宇宙交互标准接口。"
    }
  ]
}

